:root {
  --bg: #05060a;
  --panel: rgba(16, 20, 30, 0.86);
  --panel-solid: #11151f;
  --border: rgba(120, 140, 180, 0.18);
  --text: #d8e0ee;
  --muted: #8b97ad;
  --accent: #56b0ff;
  --accent2: #ffb24d;
  --danger: #ff4d4d;
  --radius: 10px;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  height: 100%;
  overflow: hidden;
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
  font-size: 13px;
}

#app { position: fixed; inset: 0; }
#app canvas { display: block; }

#labels {
  position: fixed;
  inset: 0;
  pointer-events: none;
  overflow: hidden;
  z-index: 5;
}
.planet-label {
  position: absolute;
  transform: translate(-50%, -140%);
  color: var(--text);
  font-size: 11px;
  letter-spacing: 0.3px;
  text-shadow: 0 0 6px #000, 0 0 3px #000;
  white-space: nowrap;
  opacity: 0.85;
}

/* Panels */
.panel {
  position: fixed;
  background: var(--panel);
  backdrop-filter: blur(10px);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  z-index: 10;
