+  transform: translateX(-50%);
+  width: min(720px, calc(100vw - 28px));
+  background: var(--panel);
+  backdrop-filter: blur(10px);
+  border: 1px solid var(--border);
+  border-radius: var(--radius);
+  padding: 10px 14px;
+  z-index: 10;
+}
+.tb-row { display: flex; align-items: center; gap: 8px; flex-wrap: wrap; }
+.tb-row.tiny { justify-content: space-between; color: var(--muted); margin-top: 4px; }
+.date-group { display: flex; align-items: center; gap: 6px; }
+.date-group input { width: 140px; }
+.speed-group { display: flex; align-items: center; gap: 8px; flex: 1; min-width: 160px; }
+.speed-group input { flex: 1; }
+#speed-label { min-width: 92px; text-align: right; font-size: 11px; }
+#scrub { width: 100%; margin-top: 8px; }
+#follow-indicator {
+  font-size: 11px; color: var(--accent2);
+  display: flex; align-items: center; gap: 6px;
+}
+
+/* Legend */
+#legend {
+  position: fixed;
+  bottom: 14px;
+  left: 14px;
+  background: var(--panel);
+  border: 1px solid var(--border);
+  border-radius: var(--radius);
+  padding: 8px 10px;
+  font-size: 10px;
+  z-index: 9;
+  max-width: 180px;
+}
+#legend .li { display: flex; align-items: center; gap: 6px; margin-bottom: 3px; }
+#legend .sw { width: 10px; height: 10px; border-radius: 50%; flex: none; }
+#legend h4 { margin: 0 0 6px; font-size: 10px; text-transform: uppercase; letter-spacing: 0.6px; color: var(--muted); }
+
+/* Tooltip */
+#tooltip {
+  position: fixed;
+  pointer-events: none;
+  background: rgba(8, 11, 18, 0.94);
+  border: 1px solid var(--border);
+  border-radius: 6px;
+  padding: 5px 8px;
+  font-size: 11px;
+  z-index: 20;
+  max-width: 220px;
+  transform: translate(12px, 12px);
+}
+#tooltip .t-name { font-weight: 600; }
+#tooltip .t-sub { color: var(--muted); font-size: 10px; }
+
+/* Loading */
+#loading {
+  position: fixed; inset: 0; z-index: 100;
+  background: var(--bg);
+  display: flex; align-items: center; justify-content: center;
+  transition: opacity 0.5s;
+}
+#loading.done { opacity: 0; pointer-events: none; }
+.loadbox { text-align: center; }
+.spinner {
+  width: 40px; height: 40px; margin: 0 auto 14px;
+  border: 3px solid rgba(86,176,255,0.2);
+  border-top-color: var(--accent);
+  border-radius: 50%;
+  animation: spin 0.9s linear infinite;
+}
+@keyframes spin { to { transform: rotate(360deg); } }
+#loadmsg { color: var(--muted); font-size: 12px; }
+
+/* Collapsed controls */
+#controls.collapsed .panel-body { display: none; }
+#controls.collapsed #collapse-controls { transform: rotate(180deg); }
+
+@media (max-width: 640px) {
+  #controls { width: calc(100vw - 28px); max-height: 45vh; }
+  #detail { width: calc(100vw - 28px); top: auto; bottom: 130px; max-height: 40vh; }
+  #legend { display: none; }
+}
