const $ = <T extends HTMLElement = HTMLElement>(id: string) => document.getElementById(id) as T;

const JD_MIN = dateToJD(new Date('1900-01-01T00:00:00Z'));
const JD_MAX = dateToJD(new Date('2200-01-01T00:00:00Z'));

interface Selection {
