    sorted.sort((a, b) => a.jd - b.jd);
    let t = `<table class="ca-table"><thead><tr><th>Date (TDB)</th><th>Dist (au)</th><th>Dist (LD)</th><th>v (km/s)</th></tr></thead><tbody>`;
    for (const e of sorted) {
