+      return;
+    }
+    const nowJd = time.jd;
+    // Show a window: a few past + upcoming, nearest in time first by proximity to now.
+    const sorted = [...events].sort((a, b) => Math.abs(a.jd - nowJd) - Math.abs(b.jd - nowJd)).slice(0, 12);
