+    if (a >= 365) return `${sign}${(a / 365.25).toFixed(2)} yr/s`;
+    if (a >= 1) return `${sign}${a.toFixed(1)} d/s`;
+    return `${sign}${(a * 24).toFixed(1)} h/s`;
+  }
