+    $('scrub-range').textContent = '1900 — 2200';
+
+    $('share-btn').onclick = async () => {
+      writeStateNow();
+      try {
+        await navigator.clipboard.writeText(location.href);
+        $('share-btn').textContent = 'Copied!';
+        setTimeout(() => ($('share-btn').textContent = 'Share view'), 1500);
